svg.script:
const SVG_NS = "http://www.w3.org/2000/svg";
const CENTER = 200;
const RADIUS = 195;

function initClock() {
    // Vérification que Lodash est bien chargé (car le chargement externe peut être asynchrone)
    if (typeof _ === 'undefined') {
        setTimeout(initClock, 50);
        return;
    }

    const ticksGroup = document.getElementById("ticks-group");
    const numbersGroup = document.getElementById("numbers-group");

    // Génération des 60 repères (minutes/secondes) avec Lodash
    _.times(60, (i) => {
        const line = document.createElementNS(SVG_NS, "line");
        const angle = (i * 6) * (Math.PI / 180);

        const isHour = i % 5 === 0;
        const outerR = RADIUS - 5;
        const innerR = isHour ? RADIUS - 25 : RADIUS - 12;

        line.setAttribute("x1", CENTER + innerR * Math.sin(angle));
        line.setAttribute("y1", CENTER - innerR * Math.cos(angle));
        line.setAttribute("x2", CENTER + outerR * Math.sin(angle));
        line.setAttribute("y2", CENTER - outerR * Math.cos(angle));
        line.setAttribute("stroke", isHour ? "#ffffff" : "#5c6b7f");
        line.setAttribute("stroke-width", isHour ? 3 : 1);

        ticksGroup.appendChild(line);
    });

    // Génération des chiffres (1 à 12) avec Lodash
    _.times(12, (i) => {
        const text = document.createElementNS(SVG_NS, "text");
        const num = i + 1;
        const angle = (num * 30) * (Math.PI / 180);
        const textR = RADIUS - 45;

        text.setAttribute("x", CENTER + textR * Math.sin(angle));
        text.setAttribute("y", CENTER - textR * Math.cos(angle));
        text.textContent = num;

        numbersGroup.appendChild(text);
    });

    // Lancement de l'animation
    updateClock();
}

function updateClock() {
    const hourHand = document.getElementById("hour-hand");
    const minuteHand = document.getElementById("minute-hand");
    const secondHand = document.getElementById("second-hand");

    const now = new Date();

    const seconds = now.getSeconds() + now.getMilliseconds() / 1000;
    const minutes = now.getMinutes() + seconds / 60;
    const hours = (now.getHours() % 12) + minutes / 60;

    // Utilisation de _.forEach pour mettre à jour les aiguilles
    _.forEach([
        { el: secondHand, angle: seconds * 6 },
        { el: minuteHand, angle: minutes * 6 },
        { el: hourHand,   angle: hours * 30 }
    ], ({ el, angle }) => {
        el.setAttribute("transform", "rotate(" + angle + ", " + CENTER + ", " + CENTER + ")");
    });

    requestAnimationFrame(updateClock);
}

// Initialisation au chargement du DOM SVG
document.addEventListener('DOMContentLoaded', initClock);
// Sécurité supplémentaire si le DOM est déjà chargé
if (document.readyState === 'complete' || document.readyState === 'interactive') {
    initClock();
}
